import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'sonner';
import { User, Mail, Lock, Eye, EyeOff } from 'lucide-react';

const Register = () => {
  const navigate = useNavigate();
  const { register } = useAuth();
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: '',
  });

  const handleSubmit = (e) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      toast.error('Password dan konfirmasi password tidak cocok');
      return;
    }

    if (formData.password.length < 6) {
      toast.error('Password minimal 6 karakter');
      return;
    }

    const result = register(formData.name, formData.email, formData.password, formData.phone);

    if (result.success) {
      toast.success('Registrasi berhasil! Selamat datang.');
      setTimeout(() => navigate('/'), 1000);
    } else {
      toast.error(result.message);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div
      className="min-h-screen flex"
      style={{ backgroundColor: '#0a0a0a' }}
      data-testid="register-page"
    >
      {/* Left: Truck Image — sama persis dengan Login */}
      <div className="hidden lg:flex w-[60%] relative overflow-hidden rounded-r-3xl">
        <img
          src="/images/truck-bg.jpg"
          alt="Mandiri Perkasa Logistics"
          className="w-full h-full object-cover"
        />
        <div className="absolute top-6 left-6 flex items-center gap-3">
          <img src="/images/logo.png" alt="MPL Logo" className="h-10 w-auto" />
          <span className="text-white font-bold text-xl tracking-widest uppercase">
            Mandiri Perkasa
          </span>
        </div>
      </div>

      {/* Right: Form Panel — sama persis dengan Login */}
      <div className="flex-1 flex flex-col justify-center px-10 lg:px-16 xl:px-24">
        {/* Mobile logo */}
        <div className="flex lg:hidden items-center gap-3 mb-10">
          <img src="/images/logo.png" alt="MPL Logo" className="h-8 w-auto" />
          <span className="text-white font-bold text-lg tracking-widest uppercase">
            Mandiri Perkasa
          </span>
        </div>

        <div className="max-w-sm w-full mx-auto lg:mx-0">
          {/* Title */}
          <h2
            className="text-4xl font-bold mb-3"
            style={{ color: '#D97706' }}
            data-testid="register-title"
          >
            Daftar
          </h2>
          <p className="text-gray-400 text-sm mb-8">
            Jika kamu sudah punya akun, kamu dapat{' '}
            <Link
              to="/masuk"
              className="font-semibold transition-colors"
              style={{ color: '#D97706' }}
              data-testid="login-link"
            >
              Masuk disini
            </Link>
          </p>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Email */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Email</label>
              <div className="relative flex items-center">
                <Mail className="absolute left-0 h-5 w-5" style={{ color: '#D97706' }} />
                <input
                  name="email"
                  type="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="Masukan Email Anda"
                  className="w-full pl-8 pr-3 py-2 bg-transparent text-white text-sm placeholder-gray-500 border-b border-gray-600 focus:outline-none focus:border-yellow-500 transition-colors"
                  data-testid="register-email"
                />
              </div>
            </div>

            {/* Nama Pengguna */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Nama Pengguna</label>
              <div className="relative flex items-center">
                <User className="absolute left-0 h-5 w-5" style={{ color: '#D97706' }} />
                <input
                  name="name"
                  type="text"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="Masukan Nama Pengguna"
                  className="w-full pl-8 pr-3 py-2 bg-transparent text-white text-sm placeholder-gray-500 border-b border-gray-600 focus:outline-none focus:border-yellow-500 transition-colors"
                  data-testid="register-name"
                />
              </div>
            </div>

            {/* Kata Kunci */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Kata Kunci</label>
              <div className="relative flex items-center">
                <Lock className="absolute left-0 h-5 w-5" style={{ color: '#D97706' }} />
                <input
                  name="password"
                  type={showPassword ? 'text' : 'password'}
                  required
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="Masukan Kata Sandi Anda"
                  className="w-full pl-8 pr-10 py-2 bg-transparent text-white text-sm placeholder-gray-500 border-b border-gray-600 focus:outline-none focus:border-yellow-500 transition-colors"
                  data-testid="register-password"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-0 text-gray-500 hover:text-gray-300"
                  data-testid="toggle-password"
                >
                  {showPassword ? <Eye className="h-5 w-5" /> : <EyeOff className="h-5 w-5" />}
                </button>
              </div>
            </div>

            {/* Konfirmasi Kata Sandi */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Konfirmasi Kata Sandi
              </label>
              <div className="relative flex items-center">
                <Lock className="absolute left-0 h-5 w-5" style={{ color: '#D97706' }} />
                <input
                  name="confirmPassword"
                  type={showConfirm ? 'text' : 'password'}
                  required
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  placeholder="Konfirmasi Kata Sandi Anda"
                  className="w-full pl-8 pr-10 py-2 bg-transparent text-white text-sm placeholder-gray-500 border-b border-gray-600 focus:outline-none focus:border-yellow-500 transition-colors"
                  data-testid="register-confirm-password"
                />
                <button
                  type="button"
                  onClick={() => setShowConfirm(!showConfirm)}
                  className="absolute right-0 text-gray-500 hover:text-gray-300"
                >
                  {showConfirm ? <Eye className="h-5 w-5" /> : <EyeOff className="h-5 w-5" />}
                </button>
              </div>
            </div>

            {/* Submit */}
            <div className="pt-2">
              <button
                type="submit"
                className="w-full py-3 rounded-full font-bold text-base text-black transition-colors"
                style={{ backgroundColor: '#D97706' }}
                onMouseEnter={(e) => (e.target.style.backgroundColor = '#B45309')}
                onMouseLeave={(e) => (e.target.style.backgroundColor = '#D97706')}
                data-testid="register-submit-button"
              >
                Daftar
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Register;
